import json
import hashlib
import hmac
import os
from flask import Flask, request, jsonify
from datetime import datetime

app = Flask(__name__)

# Configuration
SECRET_KEY = os.environ.get('WEBHOOK_SECRET_KEY')
ALLOWED_PARTNERS = os.environ.get('ALLOWED_PARTNERS', '').split(',')

def validate_signature(request):
    """Validate webhook signature"""
    signature = request.headers.get('X-Webhook-Signature')
    if not signature:
        return False
    
    payload = request.get_data()
    
    expected_signature = hmac.new(
        SECRET_KEY.encode('utf-8'),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_partner(partner_id):
    """Validate partner is allowed"""
    return partner_id in ALLOWED_PARTNERS

def process_payment_webhook(event_data):
    """Process payment webhook event"""
    try:
        # Extract relevant data
        partner_id = event_data.get('partner_id')
        event_type = event_data.get('event_type')
        payment_id = event_data.get('payment_id')
        amount = event_data.get('amount')
        status = event_data.get('status')
        
        # Validate partner
        if not validate_partner(partner_id):
            return {'error': 'Unauthorized partner'}, 403
        
        # Process different event types
        if event_type == 'payment.completed':
            # Handle completed payment
            print(f"Payment {payment_id} completed for {amount}")
            return {'status': 'success', 'message': 'Payment processed'}
        
        elif event_type == 'payment.failed':
            # Handle failed payment
            print(f"Payment {payment_id} failed")
            return {'status': 'success', 'message': 'Payment failed handled'}
        
        elif event_type == 'payment.refunded':
            # Handle refunded payment
            print(f"Payment {payment_id} refunded")
            return {'status': 'success', 'message': 'Refund processed'}
        
        else:
            return {'error': 'Unknown event type'}, 400
            
    except Exception as e:
        return {'error': str(e)}, 500

@app.route('/webhook/payment', methods=['POST'])
def payment_webhook():
    """HTTP endpoint for payment webhooks"""
    try:
        # Validate signature
        if not validate_signature(request):
            return jsonify({'error': 'Invalid signature'}), 401
        
        # Parse JSON data
        event_data = request.get_json()
        if not event_data:
            return jsonify({'error': 'Invalid JSON'}), 400
        
        # Process webhook
        result, status_code = process_payment_webhook(event_data)
        return jsonify(result), status_code
        
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(debug=True)